import { cn } from '@/utils/cn';
import X from 'lucide-solid/icons/x';
import { Component, createUniqueId, mergeProps } from 'solid-js';
import type { InputTextAreaProps } from '../input.types';
import { DEFAULT_PROPS, textareaVariants } from '../input.utils';

export const InputTextArea: Component<InputTextAreaProps> = (p => {
  p = mergeProps({ ...DEFAULT_PROPS, size: 'md' as const, id: createUniqueId() }, p);
  let textareaRef: HTMLTextAreaElement | undefined;

  const handleClear = (e: MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (textareaRef) {
      textareaRef.value = '';
    }
    p.onInput?.('', undefined as any);
    p.onChange?.('', undefined as any);
    textareaRef?.focus();
  };

  return (
    <div
      class={cn(
        'ta01',
        textareaVariants({ color: p.color, variant: p.variant, size: p.size }),
        p.class?.root,
        p.disabled && 'border-c5 pointer-events-none',
      )}
    >
      <textarea
        id={p.id}
        placeholder={p.placeholder}
        ref={textareaRef}
        value={p.value ?? ''}
        class={cn('text-c2 grow resize-y', p.class?.input)}
        onBlur={e => p.onBlur?.(e.currentTarget.value, e)}
        onChange={e => p.onChange?.(e.currentTarget.value, e)}
        onInput={e => p.onInput?.(e.currentTarget.value, e)}
        disabled={p.disabled}
      />
      {p.allowClear && (
        <div class="ta02" onMouseDown={handleClear}>
          <X class="m-auto size-2" />
        </div>
      )}
    </div>
  );
}) as Component<InputTextAreaProps>;
